import{_ as o,o as r,c as a,a2 as t}from"./chunks/framework.DvFsUg-r.js";const m=JSON.parse('{"title":"메뉴 관리 lego 정합 — Research","description":"","frontmatter":{"title":"메뉴 관리 lego 정합 — Research","feature_id":"015","created":"2026-06-07 13:10 (KST)","date":"2026-06-07T00:00:00.000Z"},"headers":[],"relativePath":"specs/015-lego-menu-parity/research.md","filePath":"specs/015-lego-menu-parity/research.md","lastUpdated":null}'),l={name:"specs/015-lego-menu-parity/research.md"};function d(i,e,n,s,c,u){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="research-메뉴-관리-lego-ui-ux-정합" tabindex="-1">Research: 메뉴 관리 lego UI/UX 정합 <a class="header-anchor" href="#research-메뉴-관리-lego-ui-ux-정합" aria-label="Permalink to &quot;Research: 메뉴 관리 lego UI/UX 정합&quot;">​</a></h1><p>spec 의 NEEDS CLARIFICATION 은 clarify(B)로 해소됨. 남은 기술 결정을 현재 코드 + lego 대조로 확정한다.</p><h2 id="r1-권한-모델-확장-방식-2-→-9" tabindex="-1">R1. 권한 모델 확장 방식 (2 → 9) <a class="header-anchor" href="#r1-권한-모델-확장-방식-2-→-9" aria-label="Permalink to &quot;R1. 권한 모델 확장 방식 (2 → 9)&quot;">​</a></h2><ul><li><strong>현재</strong>: <code>SYS_ROLE_MENU(ROLE_ID, MENU_ID, CAN_VIEW, CAN_EXEC)</code>. 접근통제(<code>/menus/my</code>)는 <code>CAN_VIEW=&#39;Y&#39;</code> 기준.</li><li><strong>lego</strong>: <code>SYS_ROLE_MENU(perm_read, perm_create, perm_update, perm_delete, perm_extra1..5)</code>. DTO <code>MenuPermissionDto{roleId, menuId, menuName, permRead, permCreate, permUpdate, permDelete, permExtra1..5}</code>.</li><li><strong>Decision</strong>: 신규 컬럼 <code>PERM_READ/PERM_CREATE/PERM_UPDATE/PERM_DELETE/PERM_EXTRA1..5</code> (CHAR(1) &#39;Y&#39;/&#39;N&#39;, default &#39;N&#39;) 추가. 무손실 백필 <code>PERM_READ←CAN_VIEW</code>, <code>PERM_UPDATE←CAN_EXEC</code>. 접근통제는 <code>PERM_READ</code>로 전환(동등). 기존 <code>CAN_VIEW/CAN_EXEC</code> 컬럼은 <strong>보존(deprecate)</strong>.</li><li><strong>Rationale</strong>: 드롭 없이 추가+백필이면 회귀 위험 최소. 접근통제 단언으로 동등 검증.</li><li><strong>Alternatives</strong>: (a) 컬럼 교체(드롭) — 회귀·롤백 위험 커 기각. (b) JSON 권한 컬럼 — 매트릭스 쿼리·정합성 떨어져 기각.</li></ul><h2 id="r2-메뉴-필드-정합-menu-code·component·visible" tabindex="-1">R2. 메뉴 필드 정합 (menu_code·component·visible) <a class="header-anchor" href="#r2-메뉴-필드-정합-menu-code·component·visible" aria-label="Permalink to &quot;R2. 메뉴 필드 정합 (menu_code·component·visible)&quot;">​</a></h2><ul><li><strong>현재 SYS_MENU</strong>: MENU_CODE·COMPONENT 없음, 표시여부는 <code>USE_YN</code>.</li><li><strong>Decision</strong>: <code>MENU_CODE VARCHAR(100)</code>, <code>COMPONENT VARCHAR(300)</code> 추가. <code>visible</code> 개념은 <strong>기존 <code>USE_YN</code> 재사용</strong>(신규 컬럼 안 만듦). <code>MENU_TYPE</code> 은 GROUP/MENU 유지(UI 라벨 그룹/메뉴; lego 의 D/MENU 와 의미 동등).</li><li><strong>Rationale</strong>: 표시여부 중복 컬럼 회피. 타입 라벨은 화면 매핑으로 흡수.</li><li><strong>Alternatives</strong>: lego 와 동일하게 <code>VISIBLE</code>·<code>D</code> 도입 — 기존 데이터/접근통제와 이중화되어 기각.</li></ul><h2 id="r3-순서-변경-reorder" tabindex="-1">R3. 순서 변경(reorder) <a class="header-anchor" href="#r3-순서-변경-reorder" aria-label="Permalink to &quot;R3. 순서 변경(reorder)&quot;">​</a></h2><ul><li><strong>현재</strong>: <code>PUT /api/v1/menus/reorder</code> + <code>ReorderItem(menuId, sortOrder)</code> <strong>이미 구현됨</strong>.</li><li><strong>Decision</strong>: 백엔드 작업 불필요. 프론트가 같은 부모 형제의 <code>sortOrder</code> 를 재계산해 배치 호출. 부모가 다른 노드 간 이동은 막는다(lego 동일).</li><li><strong>Rationale</strong>: 최소 변경. lego 의 swap/배치 로직을 프론트로 이식.</li></ul><h2 id="r4-트리-상호작용-드래그앤드롭·이동·펼침" tabindex="-1">R4. 트리 상호작용 (드래그앤드롭·이동·펼침) <a class="header-anchor" href="#r4-트리-상호작용-드래그앤드롭·이동·펼침" aria-label="Permalink to &quot;R4. 트리 상호작용 (드래그앤드롭·이동·펼침)&quot;">​</a></h2><ul><li><strong>Decision</strong>: lego <code>MenuTreeNode.vue</code> 의 <strong>네이티브 HTML5 DnD</strong>(dragstart/dragover/drop) <ul><li>위/아래 이동 버튼 + 펼침/접기 + 레벨 색/뱃지 + 숨김(useYn) 표시를 그대로 이식. 외부 DnD 라이브러리 도입 안 함.</li></ul></li><li><strong>Rationale</strong>: 의존성 0, 검증된 동작, 같은 부모 제약을 dataTransfer 로 구현.</li></ul><h2 id="r5-화면-분리-라우팅" tabindex="-1">R5. 화면 분리 &amp; 라우팅 <a class="header-anchor" href="#r5-화면-분리-라우팅" aria-label="Permalink to &quot;R5. 화면 분리 &amp; 라우팅&quot;">​</a></h2><ul><li><strong>Decision</strong>: 메뉴 관리 = 2화면. <code>/admin/menus</code>(트리 master-detail), <code>/admin/menu-permissions</code> (권한 매트릭스, <code>requiresAdmin</code>). 역할 관리에서 <code>?roleId=</code> 딥링크. AppShell 관리 네비에 &quot;메뉴 권한&quot; 항목 추가.</li><li><strong>Rationale</strong>: lego 구조 동일. 권한 편집을 트리 화면에서 분리해 책임 단순화.</li></ul><h2 id="r6-시각-테마" tabindex="-1">R6. 시각/테마 <a class="header-anchor" href="#r6-시각-테마" aria-label="Permalink to &quot;R6. 시각/테마&quot;">​</a></h2><ul><li><strong>Decision</strong>: 015 직전 이식한 lego 테마(<code>vuetify.ts</code>)·전역(<code>global.css</code>) 위에서 동작 — 추가 테마 작업 없음. 트리/매트릭스의 컴포넌트 스타일만 lego scoped style 이식.</li></ul><h2 id="종합" tabindex="-1">종합 <a class="header-anchor" href="#종합" aria-label="Permalink to &quot;종합&quot;">​</a></h2><p>신규 백엔드 의존 0, 신규 프론트 의존 0. 백엔드는 메뉴 도메인 컬럼·DTO·매퍼·서비스 확장 + Liquibase 마이그레이션 1건. 프론트는 트리 컴포넌트 1 + 화면 2(재작성 1·신설 1) + 라우트· 타입·API 보강. 모든 NEEDS CLARIFICATION 해소.</p>',16)])])}const E=o(l,[["render",d]]);export{m as __pageData,E as default};
